  ('heelevel3-6f0ba476-moex-00088', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-f6c431ec', 'sub-heelevel3-6f0ba476-04', NULL, 'single_choice', '有關不平衡成長理論之敘述，下列何者正確？', '["因人民之財政幻覺造成政府支出的擴大", "當私部門工資水準提升，促使政府之公務人員薪資水準也因而提高，造成公共支出的成長", "由於政府支出與私人消費一般，存在由儉入奢易，由奢返儉難的習性，導致公共支出規模日益 成長", "因社會結構改變，人口移向都市，以及人口老化等因素，使得社會對公共服務之需求日漸增加， 而擴大政府支出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "4a6aace5b1f3", "answer_pdf_sha1": "60365e8a4c1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
